import { 
  doc, getDoc, setDoc, updateDoc, onSnapshot, collection, getDocs, query, where, orderBy 
} from 'firebase/firestore';
import { createUserWithEmailAndPassword } from 'firebase/auth';
import { db, auth } from './config';

// --- ADMIN: ADD PLAYER ---
export const addPlayer = async (email, password, name) => {
  // 1. Check if email already exists in Firestore
  const q = query(collection(db, "players"), where("email", "==", email));
  const querySnapshot = await getDocs(q);
  if (!querySnapshot.empty) {
    throw new Error("A player with this email already exists!");
  }

  // 2. Create user in Firebase Auth
  const userCredential = await createUserWithEmailAndPassword(auth, email, password);
  const uid = userCredential.user.uid;

  // 3. Create document in Firestore
  await setDoc(doc(db, "players", uid), {
    uid,
    name,
    email,
    isAdmin: false,
    hasWon: false,
    wonMonth: null,
    createdAt: new Date().toISOString()
  });

  return uid;
};

// --- REAL-TIME LISTENERS ---
export const listenAuction = (callback) => {
  return onSnapshot(doc(db, 'auction', 'current'), (snap) => {
    if (snap.exists()) {
      callback(snap.data());
    } else {
      callback(null);
    }
  });
};

